
-- Create medical_journals table to store the curated whitelist of 100 journals
CREATE TABLE IF NOT EXISTS public.medical_journals (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL,
  publisher TEXT,
  category TEXT NOT NULL,
  url TEXT NOT NULL,
  impact_factor NUMERIC,
  description TEXT,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

ALTER TABLE public.medical_journals ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can read medical journals"
  ON public.medical_journals FOR SELECT
  USING (true);

CREATE INDEX IF NOT EXISTS idx_medical_journals_category ON public.medical_journals(category);

-- Insert 100 curated medical journals
ON CONFLICT DO NOTHING;

